import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"罐头笑声","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/9.消耗品/0.无支线/罐头笑声.md","filePath":"4.资源分区/7.物品与装备/9.消耗品/0.无支线/罐头笑声.md"}'),d={name:"4.资源分区/7.物品与装备/9.消耗品/0.无支线/罐头笑声.md"};function l(_,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"罐头笑声",tabindex:"-1"},[s("罐头笑声 "),e("a",{class:"header-anchor",href:"#罐头笑声","aria-label":'Permalink to "罐头笑声"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001")])])],-1),o('<h1 id="罐头笑声-1" tabindex="-1">罐头笑声 <a class="header-anchor" href="#罐头笑声-1" aria-label="Permalink to &quot;罐头笑声&quot;">​</a></h1><p>罐头笑声<br> 1500分/个<br> 录音的笑声播出来总是千篇一律的，就像罐头食品吃起来总是同一味道那样，人们将电视节目中播放的那些提前录制好的笑声称为“罐头笑声”。自其发明以来的影史来看，它一半是伟大发明，一半是噪音机器，故其售卖也分为两个版本。<br> 伟大发明:外观上来看这是一个普通的铁质方形罐头，外包装彩印着“伟大发明”四个字，罐头轻若无物，摇晃时不会发出任何声音。你可以在你社交检定失败时使用这个罐头，使用时你以一个移动动作打开罐头，罐头会迅速释放出一段录好的笑声，此笑声斑驳掺杂，各色年龄性别似乎都有。此时你只需表达出对你刚刚进行的社交内容的否定，则你的社交对象就会将其视为一次无伤大雅的玩笑，这是一个D级的心灵来源效果。并且使用者获得了再进行一次社交的机会，此次社交结果会取代上次的失败结果，但你仍然需要正常花费社交所需要的时间与动作。<br> 噪音机器:外观上来看这是一个普通的铁质圆形罐头，外包装彩印着“噪音机器”四个字，罐头轻若无物，摇晃时会发出“咚咚咚”的闷响。你可以在战斗时使用这个罐头，使用时你以一个移动动作打开罐头，罐头会迅速释放出一段录好的笑声，此笑声斑驳掺杂，各色年龄性别似乎都有，同时使用者也会不自主的随其哄堂大笑，听到的人会被其突兀且意义不明的冲击感所激怒，将其视为下一次攻击的对象，这是一个C级环境来源的胁迫效果。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
